param(
    [string]$Version = "2.41.6",
    [string]$Python = "python",
    [switch]$SkipSmokeTest
)

$ErrorActionPreference = "Stop"
$Root = Resolve-Path (Join-Path $PSScriptRoot "..")
$Runtime = Join-Path $Root "runtime"
$Venv = Join-Path $Runtime "venv"
$Logs = Join-Path $Root "logs"
$ConfigDir = Join-Path $Root "config"
$ConfigPath = Join-Path $ConfigDir "arelle.config.php"

New-Item -ItemType Directory -Force -Path $Runtime, $Logs, $ConfigDir | Out-Null

function Write-Step([string]$Message) {
    Write-Host "[Arelle] $Message"
}

function Assert-PythonVersion([string]$PythonCommand) {
    $versionOutput = & $PythonCommand -c "import sys; print(f'{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}')" 2>&1
    if ($LASTEXITCODE -ne 0) {
        throw "Python command failed: $versionOutput"
    }

    $parts = "$versionOutput".Trim().Split(".")
    $major = [int]$parts[0]
    $minor = [int]$parts[1]
    if ($major -lt 3 -or ($major -eq 3 -and $minor -lt 10)) {
        throw "Arelle requires Python >= 3.10. Found $versionOutput."
    }

    Write-Step "Using Python $versionOutput"
}

Write-Step "Checking Python"
Assert-PythonVersion $Python

if (!(Test-Path $Venv)) {
    Write-Step "Creating virtual environment at $Venv"
    & $Python -m venv $Venv
    if ($LASTEXITCODE -ne 0) {
        throw "Could not create Python virtual environment."
    }
}

$VenvPython = Join-Path $Venv "Scripts\python.exe"
$ArelleCmd = Join-Path $Venv "Scripts\arelleCmdLine.exe"

Write-Step "Upgrading pip in local runtime"
& $VenvPython -m pip install --upgrade pip
if ($LASTEXITCODE -ne 0) {
    throw "pip upgrade failed."
}

Write-Step "Installing arelle-release==$Version"
& $VenvPython -m pip install "arelle-release==$Version"
if ($LASTEXITCODE -ne 0) {
    throw "Arelle install failed."
}

if (!(Test-Path $ArelleCmd)) {
    throw "Arelle command was not found at $ArelleCmd"
}

$escapedArelle = $ArelleCmd.Replace("\", "\\")
$escapedLogs = $Logs.Replace("\", "\\")
$config = @"
<?php
/**
 * Local Arelle configuration generated by install_arelle.ps1.
 * This file is machine-specific and intentionally ignored by git.
 */
declare(strict_types=1);

return [
    'enabled' => true,
    'arelle_cmd' => '$escapedArelle',
    'timeout_seconds' => 180,
    'logs_path' => '$escapedLogs',
    'packages' => [],
    'flags' => ['--validate'],
];
"@
Set-Content -Path $ConfigPath -Value $config -Encoding ASCII
Write-Step "Wrote config to $ConfigPath"

if (!$SkipSmokeTest) {
    Write-Step "Running smoke tests"
    & (Join-Path $PSScriptRoot "test_arelle.ps1")
    if ($LASTEXITCODE -ne 0) {
        throw "Arelle smoke test failed."
    }
}

Write-Step "Install complete"
